  ('social-worker-moex-01561', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列所敘述之社會工作目的，何者錯誤？', '["運用社會工作的專業知能協助服務對象連結所需資源", "經由社會工作的服務過程增強服務對象的問題解決和因應能力", "社會工作者以提高社會工作的專業地位為最重要工作", "社會工作促成社會政策的發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01562', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1917年出版的社會診斷（Social Diagnosis）一書對社會工作的專業發展奠定基礎，下列何者為社 會診斷（Social Diagnosis）一書的作者？', '["Gordon Hamilton", "Florence Hollis", "Jane Addams", "Mary Richmond"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01563', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作是一門以助人為目的的專業，對於人的本質與人性需求、人類福祉的觀念需與時俱進， 社會工作的專業內涵與定義亦隨時間與地區而有所差異。在1956年美國社會工作協會（NASW） 對「社會工作實施的工作定義」，將社會工作視為：一種負責的、有意識的、有訓練的運用自我 與個人、團體的關係，藉此催化個人與其環境的互動，並持續覺察兩者的交互影響。若依據以上 定義，社會工作服務的效能，係以下列何者為關鍵？', '["知識", "關係", "影響", "改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01564', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依據Morales與Sheafor（1998），社會工作的目的有3C，請問是那3C？①治療  ②照顧  ③挑', '["改變社會", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01565', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '兒童保護領域社會工作者為個案評估需求、決定提供那些服務、聯絡安置機構、倡導相關照護資 源、協助案家尋找社會住宅、提供個案諮商服務以及與醫院共同合作，並追蹤其服務使用成效。 此工作內容最符合何項專業角色？', '["個案管理者", "諮商者", "倡導者", "團體催化者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01566', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '發掘社會資源及啟發個人潛能，積極拓展案主的社會生活。上述屬於那一項社會工作的核心功 能？', '["恢復功能", "預防功能", "發展功能", "控制功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01567', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Healy, K.（2005）提出三項觀點說明「理論建構」在社會工作專業發展的位置，下列何者錯 誤？', '["社會工作者無暇發展實務研究，可直觀地運用經驗處遇", "社會工作者必須向服務使用者與經費提供者負責", "社會工作者必須能不斷改善服務品質", "社會工作者有責任去參與專業理論的發展，以促進專業不斷進步"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01568', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關心理暨社會學派對人類行為與社會適應問題產生的基本假定，何者正確？①人格與個人', '["人類生活環境為一個系統，系統內的成員彼此交互反應和相互影響，成為 一個連鎖反應", "要預測人的行為，了解人的內在心理就可以了", "人之所以會發生適應問題是 來自社會適應失敗", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01569', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何組合為認知行為取向工作方法：①挑戰求助者對困境的解釋  ②運用自由聯想的方式找出', '["與求助者一起思考替代對困境原有的解釋", "充權案主挑戰制度上的 種族歧視  ⑤處理求助者此時此刻狀況", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
